    def _classify_domain(self, domain: str) -> str:
        """Classify domain type based on TLD"""
        tld = domain.split('.')[-1]
        if tld in ['com', 'net', 'org']:
            return 'commercial'
        elif tld in ['edu', 'gov', 'mil']:
