                    headers={'User-Agent': 'Mozilla/5.0'},
                    timeout=10
                )
                if response.status_code == 200:
                    social_data['platforms'].append({
                        'platform': platform['name'],
                        'found': True,
                        'url': platform['url']
                    })
                    social_data['total_accounts'] += 1
            except requests.RequestException:
                continue

        social_data['visibility_score'] = min(100, social_data['total_accounts'] * 25)
        return social_data

    def collect_domain_records(self) -> Dict:
