                logger.error(f"Bomb execution failed: {self.config.name}")
                return False

        except Exception as e:
            logger.error(f"Trigger execution error: {str(e)}")
            self.state.error_message = str(e)
            return False

    def _validate_configuration(self) -> bool:
        """Validate bomb configuration"""
        try:
            # Check required fields
            required_fields = ['bomb_id', 'name', 'trigger_type', 'action_type']
            for field in required_fields:
                if not hasattr(self.config, field):
                    logger.error(f"Missing required field: {field}")
                    return False

            # Validate trigger condition
            if not self.config.trigger_condition:
                logger.error("Trigger condition is empty")
                return False

            # Validate action payload
            if not self.config.action_payload:
                logger.error("Action payload is empty")
                return False

            # Validate time constraints
            if self.config.activation_time > datetime.now():
                logger.warning(f"Bomb activation time is in the future: {self.config.activation_time}")

            return True

        except Exception as e:
            logger.error(f"Configuration validation error: {str(e)}")
            return False

    def _start_monitoring(self):
        """Start background monitoring thread"""
        def monitoring_loop():
            while not self._stop_event.is_set():
                try:
                    self._check_trigger()
                    self._collect_metrics()
                    self._stop_event.wait(timeout=60)  # Check every 60 seconds

                except Exception as e:
                    logger.error(f"Monitoring error: {str(e)}")
                    self._stop_event.wait(timeout=300)  # Wait 5 minutes before retry

        self._thread = threading.Thread(target=monitoring_loop, daemon=True)
        self._thread.start()
        logger.info("Monitoring thread started")

    def _check_trigger(self) -> bool:
        """Check if trigger conditions are met"""
        try:
            current_time = datetime.now()

            # Check if bomb should be active
            if current_time < self.config.activation_time:
                return False

            # Check expiration
            if self.config.expiration_time and current_time > self.config.expiration_time:
                self.state.status = 'expired'
                logger.info(f"Bomb expired: {self.config.name}")
                return False

            # Evaluate trigger based on type
            if self.config.trigger_type == BombTriggerType.TIME_BASED:
                return self._check_time_trigger()
            elif self.config.trigger_type == BombTriggerType.EVENT_BASED:
                return self._check_event_trigger()
            elif self.config.trigger_type == BombTriggerType.CONDITION_BASED:
                return self._check_condition_trigger()
            elif self.config.trigger_type == BombTriggerType.NETWORK_BASED:
                return self._check_network_trigger()
            elif self.config.trigger_type == BombTriggerType.FILE_BASED:
                return self._check_file_trigger()

            return False

        except Exception as e:
            logger.error(f"Trigger check error: {str(e)}")
            return False

    def _check_time_trigger(self) -> bool:
        """Check time-based trigger conditions"""
        try:
            trigger_time = self.config.trigger_condition.get('trigger_time')
            if trigger_time:
                trigger_dt = datetime.fromisoformat(trigger_time)
                if datetime.now() >= trigger_dt:
                    return True
            return False
        except Exception as e:
            logger.error(f"Time trigger check error: {str(e)}")
            return False

