    def _evaluate_condition(self, condition: Dict) -> bool:
        """Evaluate a single condition"""
        try:
            condition_type = condition.get('type')
            condition_value = condition.get('value')
            operator = condition.get('operator', 'equals')

            # Get current value based on condition type
            current_value = self._get_current_value(condition_type)

            # Evaluate based on operator
            if operator == 'equals':
                return current_value == condition_value
            elif operator == 'greater_than':
                return current_value > condition_value
            elif operator == 'less_than':
                return current_value < condition_value
            elif operator == 'contains':
                return condition_value in str(current_value)
            elif operator == 'regex_match':
                import re
                return bool(re.search(condition_value, str(current_value)))

            return False

        except Exception as e:
            logger.error(f"Condition evaluation error: {str(e)}")
            return False

    def _get_current_value(self, condition_type: str) -> any:
        """Get current value for a condition type"""
        try:
            if condition_type == 'system_load':
                return os.getloadavg()[0] if hasattr(os, 'getloadavg') else 0.5
            elif condition_type == 'memory_usage':
                import psutil
                return psutil.virtual_memory().percent
            elif condition_type == 'disk_usage':
                import psutil
                return psutil.disk_usage('/').percent
            elif condition_type == 'process_count':
                return len([p for p in subprocess.run(['ps', 'aux'], capture_output=True).stdout.decode().split('\n')])
            elif condition_type == 'network_connections':
                return len([conn for conn in socket.getaddrinfo('localhost', 80)])
            else:
                return 0
        except Exception as e:
            logger.error(f"Value retrieval error: {str(e)}")
            return 0

