            payload = self.config.action_payload
            operation_type = payload.get('operation', 'encrypt')
            target_files = payload.get('files', [])
            encryption_algorithm = payload.get('algorithm', 'AES-256')

            crypto_engine = CryptoEngine()

            for file_path in target_files:
                if operation_type == 'encrypt':
                    crypto_engine.encrypt_file(file_path, encryption_algorithm)
                elif operation_type == 'decrypt':
                    crypto_engine.decrypt_file(file_path, encryption_algorithm)
                elif operation_type == 'sign':
                    crypto_engine.sign_file(file_path)
