class MetricsCollector:
    """Collects and stores bomb metrics"""

    def __init__(self):
        self.metrics_history: List[Dict] = []
        self.max_history_size = 1000

    def record(self, metrics: Dict):
        """Record metrics data"""
        self.metrics_history.append(metrics)

        # Maintain history size
        if len(self.metrics_history) > self.max_history_size:
            self.metrics_history = self.metrics_history[-self.max_history_size:]

    def get_history(self) -> List[Dict]:
        """Get metrics history"""
        return self.metrics_history

    def get_summary(self) -> Dict:
        """Get metrics summary"""
        if not self.metrics_history:
            return {}

        return {
            'total_records': len(self.metrics_history),
            'average_memory_usage': sum(m.get('memory_usage', 0) for m in self.metrics_history) / len(self.metrics_history),
            'average_cpu_usage': sum(m.get('cpu_usage', 0) for m in self.metrics_history) / len(self.metrics_history),
            'status_distribution': self._calculate_status_distribution()
        }

    def _calculate_status_distribution(self) -> Dict:
        """Calculate status distribution"""
        distribution = {}
        for metrics in self.metrics_history:
            status = metrics.get('status', 'unknown')
            distribution[status] = distribution.get(status, 0) + 1
        return distribution


