class NetworkMonitor:
    """Monitors network conditions for trigger detection"""

    def __init__(self):
        self.network_stats: Dict = {}

    def check_network_conditions(self, config: Dict) -> bool:
        """Check network conditions based on configuration"""
        try:
            conditions = config.get('conditions', [])

            for condition in conditions:
                condition_type = condition.get('type')
                threshold = condition.get('threshold')

                if condition_type == 'latency':
                    if not self._check_latency(threshold):
                        return False
                elif condition_type == 'bandwidth':
                    if not self._check_bandwidth(threshold):
                        return False
                elif condition_type == 'connection_count':
                    if not self._check_connection_count(threshold):
                        return False
                elif condition_type == 'packet_loss':
                    if not self._check_packet_loss(threshold):
                        return False

            return True
        except Exception as e:
            logger.error(f"Network condition check error: {str(e)}")
            return False

    def _check_latency(self, threshold_ms: int) -> bool:
        """Check network latency"""
        try:
            import subprocess
            result = subprocess.run(['ping', '-c', '3', '8.8.8.8'], 
                                  capture_output=True, text=True)
            if result.returncode == 0:
                # Parse ping output for average latency
                output = result.stdout
                avg_latency = float(output.split('avg=')[1].split('/')[0])
                return avg_latency <= threshold_ms
            return False
        except Exception:
            return False

    def _check_bandwidth(self, threshold_mbps: float) -> bool:
        """Check network bandwidth"""
        try:
            import psutil
            net_io = psutil.net_io_counters()
            # Calculate bandwidth in Mbps
            bandwidth = (net_io.bytes_sent + net_io.bytes_recv) / (1024 * 1024 * 8)
            return bandwidth >= threshold_mbps
        except Exception:
            return False

    def _check_connection_count(self, threshold: int) -> bool:
        """Check active connection count"""
        try:
            import psutil
            connections = psutil.net_connections(kind='inet')
            active_connections = len([c for c in connections if c.status == 'ESTABLISHED'])
            return active_connections >= threshold
        except Exception:
            return False

    def _check_packet_loss(self, threshold_percent: float) -> bool:
        """Check packet loss percentage"""
        try:
            import subprocess
            result = subprocess.run(['ping', '-c', '10', '8.8.8.8'], 
                                  capture_output=True, text=True)
            if result.returncode == 0:
                output = result.stdout
                # Parse packet loss from ping output
                if 'packet loss' in output:
                    loss = float(output.split('packet loss')[1].split('%')[0])
                    return loss <= threshold_percent
            return False
        except Exception:
            return False


