BOOL StopService(HANDLE hService, const char* serviceName) {
    SERVICE_STATUS status;
    DWORD dwWaitTime = 5000;
    DWORD dwStart = GetTickCount();

    LogMessage("INFO", "Stopping service: %s", serviceName);

    if (!ControlService(hService, SERVICE_CONTROL_STOP, &status)) {
        LogMessage("ERROR", "ControlService failed for %s: %lu", serviceName, GetLastError());
        return FALSE;
    }

    while (status.dwCurrentState == SERVICE_STOP_PENDING) {
        if (GetTickCount() - dwStart > dwWaitTime) {
            LogMessage("WARN", "Service %s stop timeout", serviceName);
            break;
        }

        Sleep(1000);
        if (!QueryServiceStatus(hService, &status)) {
            LogMessage("ERROR", "QueryServiceStatus failed: %lu", GetLastError());
            return FALSE;
        }
    }

    if (status.dwCurrentState == SERVICE_STOPPED) {
        LogMessage("INFO", "Service %s stopped successfully", serviceName);
        return TRUE;
