                ctx.stroke();

                // Draw threat icon
                ctx.fillStyle = 'white';
                ctx.font = '18px Arial';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillText(this.isNeutralized ? '✅' : '⚠️', this.x, this.y);

                // Draw health bar
                if (!this.isNeutralized) {
                    const barWidth = 40;
                    const barHeight = 6;
                    const barX = this.x - barWidth / 2;
                    const barY = this.y - this.radius - 15;

                    ctx.fillStyle = '#ecf0f1';
                    ctx.fillRect(barX, barY, barWidth, barHeight);

                    ctx.fillStyle = '#27ae60';
                    ctx.fillRect(barX, barY, barWidth * (this.health / 100), barHeight);
                }
            }

            neutralize() {
                this.isNeutralized = true;
                gameState.score += CONFIG.scorePerThreat;
                gameState.threatsNeutralized++;
                showNotification(`Threat Neutralized! +${CONFIG.scorePerThreat} points`);
            }
        }

        class Particle {
            constructor(x, y, color) {
                this.x = x;
                this.y = y;
                this.color = color;
                this.radius = Math.random() * 5 + 2;
                this.speed = Math.random() * 3 + 1;
                this.direction = {
                    x: Math.random() * 2 - 1,
                    y: Math.random() * 2 - 1
                };
                this.life = 100;
                this.decay = Math.random() * 2 + 1;
            }

            update() {
                this.x += this.direction.x * this.speed;
                this.y += this.direction.y * this.speed;
                this.life -= this.decay;
            }

            draw() {
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
                ctx.fillStyle = this.color;
                ctx.globalAlpha = this.life / 100;
                ctx.fill();
                ctx.globalAlpha = 1;
            }
        }

        // Game Objects
        let player = new Player();
        let civilians = [];
        let threats = [];
        let particles = [];

        // Input Handling
        const keys = {};

        document.addEventListener('keydown', (e) => {
            keys[e.key] = true;

            if (e.key === ' ' && gameState.isRunning && !gameState.isPaused) {
                player.activateShield();
            }

            if (e.key === 'e' || e.key === 'E') {
                player.activateScan();
            }
        });

        document.addEventListener('keyup', (e) => {
            keys[e.key] = false;
        });

        // Game Functions
        function startGame() {
            document.getElementById('startOverlay').classList.add('hidden');
            gameState.isRunning = true;
            gameState.startTime = Date.now();
            gameState.lastSpawnTime = Date.now();
            gameState.lastWaveTime = Date.now();

            // Initial spawns
            for (let i = 0; i < 3; i++) {
                civilians.push(new Civilian());
            }
            for (let i = 0; i < 2; i++) {
                threats.push(new Threat());
            }

            gameLoop();
        }

        function restartGame() {
            document.getElementById('gameOverOverlay').classList.add('hidden');
            player = new Player();
            civilians = [];
            threats = [];
            particles = [];
            gameState.score = 0;
            gameState.lives = CONFIG.maxLives;
            gameState.wave = 1;
            gameState.civiliansProtected = 0;
            gameState.threatsNeutralized = 0;
            gameState.startTime = Date.now();
            gameState.lastSpawnTime = Date.now();
            gameState.lastWaveTime = Date.now();

            startGame();
        }

        function togglePause() {
            gameState.isPaused = !gameState.isPaused;
        }

        function spawnCivilian() {
            if (gameState.isRunning && !gameState.isPaused) {
                civilians.push(new Civilian());
                showNotification('New Civilian Deployed!');
            }
        }

        function spawnThreat() {
            if (gameState.isRunning && !gameState.isPaused) {
                threats.push(new Threat());
                showNotification('New Threat Detected!');
            }
        }

        function showInstructions() {
            alert('🎮 War & Humanity - Instructions\n\n' +
                  '🛡️ PROTECT CIVILIANS: Guide civilians to the safety zone (center of map)\n' +
                  '⚔️ NEUTRALIZE THREATS: Intercept hostile forces to protect civilians\n' +
                  '🎯 CONTROLS:\n' +
                  '   - WASD/Arrows: Move tactical unit\n' +
                  '   - Space: Activate protective shield\n' +
                  '   - Shift: Enhanced defense mode\n' +
                  '   - E: Scan area for threats\n\n' +
                  '📊 SCORING:\n' +
                  '   - Civilian Protected: +100 points\n' +
                  '   - Threat Neutralized: +50 points\n' +
                  '   - Wave Completion: Bonus points\n\n' +
                  '🎯 MISSION: Balance offensive and defensive actions to maximize humanitarian impact!');
        }

        function showNotification(message) {
            const notification = document.createElement('div');
            notification.className = 'notification';
            notification.textContent = message;
            document.body.appendChild(notification);

            setTimeout(() => {
                notification.remove();
            }, 3000);
        }

        function updatePlayerPosition() {
            if (keys['w'] || keys['ArrowUp']) {
                player.y = Math.max(player.radius, player.y - CONFIG.playerSpeed);
            }
            if (keys['s'] || keys['ArrowDown']) {
                player.y = Math.min(CONFIG.canvasHeight - player.radius, player.y + CONFIG.playerSpeed);
            }
            if (keys['a'] || keys['ArrowLeft']) {
                player.x = Math.max(player.radius, player.x - CONFIG.playerSpeed);
            }
            if (keys['d'] || keys['ArrowRight']) {
                player.x = Math.min(CONFIG.canvasWidth - player.radius, player.x + CONFIG.playerSpeed);
            }
        }

        function checkCollisions() {
            // Check civilian-player collisions
            civilians.forEach(civilian => {
                const dx = player.x - civilian.x;
                const dy = player.y - civilian.y;
                const distance = Math.sqrt(dx * dx + dy * dy);

                if (distance < player.radius + civilian.radius) {
                    if (player.isShielded) {
                        civilian.isSafe = true;
                        gameState.score += CONFIG.scorePerCivilian;
                        gameState.civiliansProtected++;
                        createParticles(civilian.x, civilian.y, '#2ecc71');
                    }
                }
            });

            // Check threat-player collisions
            threats.forEach(threat => {
                const dx = player.x - threat.x;
                const dy = player.y - threat.y;
                const distance = Math.sqrt(dx * dx + dy * dy);

                if (distance < player.radius + threat.radius) {
                    if (player.isShielded) {
                        threat.neutralize();
                        createParticles(threat.x, threat.y, '#e74c3c');
                    } else {
                        gameState.lives--;
                        threat.neutralize();
                        createParticles(threat.x, threat.y, '#e74c3c');
                        showNotification('⚠️ Threat Impact! Lives: ' + gameState.lives);
                    }
                }
            });

            // Check civilian-threat collisions
            civilians.forEach(civilian => {
                threats.forEach(threat => {
                    const dx = civilian.x - threat.x;
                    const dy = civilian.y - threat.y;
                    const distance = Math.sqrt(dx * dx + dy * dy);

                    if (distance < civilian.radius + threat.radius) {
                        if (!civilian.isSafe && !threat.isNeutralized) {
                            civilian.isSafe = false;
                            gameState.lives--;
                            showNotification('⚠️ Civilian Impact! Lives: ' + gameState.lives);
                            createParticles(civilian.x, civilian.y, '#e74c3c');
                        }
                    }
                });
            });
        }

        function createParticles(x, y, color) {
            for (let i = 0; i < 10; i++) {
                particles.push(new Particle(x, y, color));
            }
        }

        function updateUI() {
            document.getElementById('score').textContent = gameState.score;
            document.getElementById('lives').textContent = gameState.lives;
            document.getElementById('wave').textContent = gameState.wave;

            const elapsed = Math.floor((Date.now() - gameState.startTime) / 1000);
            const minutes = Math.floor(elapsed / 60).toString().padStart(2, '0');
            const seconds = (elapsed % 60).toString().padStart(2, '0');
            document.getElementById('time').textContent = `${minutes}:${seconds}`;
        }

        function checkGameEnd() {
            if (gameState.lives <= 0) {
                gameState.isRunning = false;
                document.getElementById('finalScore').textContent = `Final Score: ${gameState.score}`;
                document.getElementById('finalStats').textContent = 
                    `Civilians Protected: ${gameState.civiliansProtected} | Threats Neutralized: ${gameState.threatsNeutralized}`;
                document.getElementById('gameOverOverlay').classList.remove('hidden');
            }
        }

        function gameLoop() {
            if (!gameState.isRunning || gameState.isPaused) return;

            const deltaTime = Date.now() - gameState.lastSpawnTime;

            // Clear canvas
            ctx.fillStyle = '#2c3e50';
            ctx.fillRect(0, 0, CONFIG.canvasWidth, CONFIG.canvasHeight);

            // Draw grid
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
            ctx.lineWidth = 1;
            for (let x = 0; x < CONFIG.canvasWidth; x += 50) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, CONFIG.canvasHeight);
                ctx.stroke();
            }
            for (let y = 0; y < CONFIG.canvasHeight; y += 50) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(CONFIG.canvasWidth, y);
                ctx.stroke();
            }

            // Draw safety zone
            ctx.beginPath();
            ctx.arc(CONFIG.canvasWidth / 2, CONFIG.canvasHeight / 2, 100, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(39, 174, 96, 0.2)';
            ctx.fill();
            ctx.strokeStyle = 'rgba(39, 174, 96, 0.5)';
            ctx.lineWidth = 3;
            ctx.stroke();

            // Update and draw entities
            updatePlayerPosition();
            player.update(deltaTime);
            player.draw();

            civilians.forEach(civilian => {
                civilian.update();
                civilian.draw();
            });

            threats.forEach(threat => {
                threat.update();
                threat.draw();
            });

            particles.forEach((particle, index) => {
                particle.update();
                particle.draw();
                if (particle.life <= 0) {
                    particles.splice(index, 1);
                }
            });

            checkCollisions();
            updateUI();
            checkGameEnd();

            // Spawn new entities
            if (deltaTime > CONFIG.spawnInterval) {
                if (Math.random() > 0.5) {
                    civilians.push(new Civilian());
                } else {
                    threats.push(new Threat());
                }
                gameState.lastSpawnTime = Date.now();
            }

            // Wave progression
            const waveTime = Date.now() - gameState.lastWaveTime;
            if (waveTime > CONFIG.waveInterval) {
                gameState.wave++;
                gameState.lastWaveTime = Date.now();
                showNotification(`🌊 Wave ${gameState.wave} Started!`);
            }

            gameState.lastSpawnTime = Date.now();
            requestAnimationFrame(gameLoop);
        }

        // Initialize
        window.addEventListener('load', () => {
            console.log('War & Humanity: Civilian Protection Game Loaded');
        });
    </script>
</body>
</html>
